#include<bits/stdc++.h>
using namespace std;
int x[1001];
int main()
{
	int n,k;
	cin>>k>>n;
	int s=0,v=0;
	for(int i=0;i<n;i++)cin>>x[i];
	while(s<k){
		v++;
		s+=v;
	}
	for(int i=0;i<n;i++){
		if(x[i]>=v)cout<<v<<endl;
		else{
			double he=999999999;
			for(int h=0;;h++){
				int red,blue,green;
				red=x[i]*(x[i]-1)/2;
				blue=((h+x[i])+x[i])*(h+1)-(h+x[i]);
				green=k-red-blue;
				if(green<0)break;
				he=min(he,2*h+x[i]+ceil(1.0*green/(h+x[i])));
			}	
			cout<<he<<endl;		
		}
	}
	
}
